function() {
  try {
    var ua = navigator.userAgent || "";
    var isMobileUA = /Mobi|Android|iPhone|iPad|iPod/i.test(ua);
    var isMobileWidth = false;
    try {
      isMobileWidth = window.matchMedia("(max-width: 767px)").matches;
    } catch (e) {
      isMobileWidth = true;
    }
    if (isMobileUA && isMobileWidth) {
      return "true";
    }
  } catch (e) {
    return "false";
  }
  return "false";
}

function() {
  var ts = Date.now();
  var rand = Math.floor(Math.random() * 1e8);
  return ts + '_' + rand;
}

