    } else if (rule === 'cookie_begins_with') {
      exemptedCookiesNamesBeginWith.push(value);
    } else if (rule === 'cookie_ends_with') {
      exemptedCookiesNamesEndWith.push(value);
    } else if (rule === 'cookie_contains') {
      exemptedCookiesNamesContain.push(value);
    }
